1	//! R6 — the interactive server's WEB rendering mode of theory content.
2	//!
3	//! The `main/message` and `main/rules` pane BODIES render the SAME blocks the
4	//! batch echo models, but: at width 100 / ribbon 67 (the default HughesPJ
5	//! `Style`, not the batch 110/73); HTML-entity-escaped; with keyword / operator
6	//! / comment tokens wrapped in `<span class="hl_…">`; and WITHOUT the batch
7	//! signature header comment. See workspace/BEHAVIOR.md "Web mode (R6)" for the
8	//! capture provenance of every rule below.
9	//!
10	//! ONE model, TWO render targets. The block-doc builders in `term` /
11	//! `signature` / `rule` / `formula` / `lemma` emit ALL of their text through the
12	//! web-aware [`w_text`] / [`w_char`] constructors, and their styled glyphs
13	//! additionally through the [`hl_kw`] / [`hl_op_char`] / [`hl_op_text`] /
14	//! [`hl_comment`] / [`hl_wrap`] wrappers here. In batch mode (the default)
15	//! [`w_text`]/[`w_char`] ARE `doc::text`/`doc::char` and each `hl_*` wrapper is
16	//! the identity — the R1–R5 output is byte-for-byte unchanged. In web mode
17	//! (inside [`html_render`]) the `hl_*` wrappers add a zero-width span-marker pair
18	//! — mirroring the sanctioned `Annotated.HughesPJ` `AnnotStart`/`AnnotEnd`:
19	//! `sized_text(0, …)` sentinels that flow through best/fits/lay at zero width.
20	//!
21	//! **Escaped-width layout.** In web mode every visible token is laid out at its
22	//! ENTITY-ESCAPED width, not its glyph width: the layout engine measures what the
23	//! output actually shows after escaping (`<`/`>` = 4 columns, `&` = 5, `"` = 6,
24	//! `'` = 5, every other visible char = 1). [`w_text`]/[`w_char`] realise this by
25	//! sizing the token to its escaped length while keeping the raw glyph as content
26	//! ([`crate::doc::sized_text`] supports that size-vs-content divergence). So
27	//! wrap/fit decisions for rule bodies, bracket groups, quantifier / formula
28	//! groups and the pair/AC/application fills all judge fit on the escaped form —
29	//! equivalently, escape first, then lay out. [`html_render`] renders at (100, 67)
30	//! and runs one pass that entity-escapes the raw text and expands the sentinels
31	//! into the spans. The span markers stay zero-width, so they never affect layout.
32	
33	use std::cell::Cell;
34	
35	use crate::ast::{AcVariants, Restriction, Rule, Signature};
36	use crate::doc::{beside_op, char, render_with, sized_text, text, Doc};
37	use crate::{formula, lemma, rule, signature};
38	
39	/// Web layout parameters — width 100, ribbon 67 (the default HughesPJ `Style`:
40	/// `lineLength = 100`, `ribbonsPerLine = 1.5`, `round(100/1.5) = 67`). Combined
41	/// with the escaped-width sizing of [`w_text`]/[`w_char`], these reproduce the
42	/// captured wrap thresholds exactly: the signature `fsep` fills (no escapable
43	/// chars, so escaped width = glyph width) reach absolute 78 = nest 11 + ribbon
44	/// 67, while a nest-3 rule body wraps once its ESCAPED width exceeds 67 — a
45	/// content-66 body carrying an arrow (`]->` charges its `>` at 4, escaped 69)
46	/// wraps, whereas a content-66 bracket group with no escapable chars (escaped
47	/// 66) keeps its `]`. The same escaped measurement forces the pair/AC/app
48	/// delimiter drops. Census provenance: QUERIES.log R7 (one-line max escaped 67 /
49	/// wrapped min 69, zero exceptions).
50	pub const WEB_WIDTH: isize = 100;
51	pub const WEB_RIBBON: isize = 67;
52	
53	// ── span markers (zero-width sentinels; expanded by `escape_and_expand`) ──────
54	//
55	// Control chars that never occur in theory content (no C0 controls in the
56	// corpus), so they survive the entity-escape pass untouched and are then
57	// expanded into span tags.
58	const M_OPEN: char = '\u{1}'; //  \u{1}<class>\u{2}  ->  <span class="<class>">
59	const M_SEP: char = '\u{2}';
60	const M_CLOSE: char = '\u{3}'; //  \u{3}            ->  </span>
61	
62	thread_local! {
63	    static HL: Cell<bool> = const { Cell::new(false) };
64	}
65	
66	fn hl_on() -> bool {
67	    HL.with(|c| c.get())
68	}
69	
70	/// RAII: enable web-mode styling for the duration of a doc build, restoring the
71	/// previous state on drop (so nesting and panics leave the flag consistent).
72	struct HlGuard(bool);
73	impl HlGuard {
74	    fn on() -> Self {
75	        HlGuard(HL.with(|c| c.replace(true)))
76	    }
77	}
78	impl Drop for HlGuard {
79	    fn drop(&mut self) {
80	        HL.with(|c| c.set(self.0));
81	    }
82	}
83	
84	/// Wrap `d` in a zero-width span-marker pair carrying `class`.
85	fn annot(class: &str, d: Doc) -> Doc {
86	    let open = format!("{M_OPEN}{class}{M_SEP}");
87	    let close = M_CLOSE.to_string();
88	    beside_op(sized_text(0, &open), beside_op(d, sized_text(0, &close)))
89	}
90	
91	// ── escaped-width sizing (web mode) ──────────────────────────────────────────
92	
93	/// The column width a character occupies AFTER the entity escaping applied by
94	/// [`escape_and_expand`]: the length of its escaped form. Any character that is
95	/// not escaped keeps width 1 (non-ASCII glyphs `∀ ∃ ⇒ …` are one scalar each and
96	/// pass raw). This is THE production layout charge.
97	fn escaped_char_width(c: char) -> usize {
98	    match c {
99	        '<' | '>' => 4, // &lt; &gt;
100	        '&' => 5,       // &amp;
101	        '"' => 6,       // &quot;
102	        '\'' => 5,      // &#39;
103	        _ => 1,
104	    }
105	}
106	
107	thread_local! {
108	    /// The per-character layout charge, [`escaped_char_width`] in all normal
109	    /// operation. Indirected through a cell so the acceptance suite alone can
110	    /// DOCTOR it (e.g. to glyph width) and prove the byte gate genuinely depends
111	    /// on the escaped charging — see `escaped_charging_is_load_bearing`.
112	    static CHARGE: Cell<fn(char) -> usize> = Cell::new(escaped_char_width);
113	}
114	
115	/// The active layout charge for one character (the escaped width in production).
116	fn char_charge(c: char) -> usize {
117	    CHARGE.with(|k| k.get())(c)
118	}
119	
120	/// Layout charge for a whole string (sum of per-character charges).
121	fn escaped_width(s: &str) -> usize {
122	    s.chars().map(char_charge).sum()
123	}
124	
125	/// Web-aware `text`: in web mode the token is sized to its ESCAPED width while
126	/// its raw glyphs stay as the content (escaped later by [`escape_and_expand`]),
127	/// so the layout engine measures the escaped form. In batch mode it is exactly
128	/// `doc::text` — the R1–R5 output is byte-for-byte unchanged.
129	pub(crate) fn w_text(s: &str) -> Doc {
130	    if hl_on() {
131	        sized_text(escaped_width(s), s)
132	    } else {
133	        text(s)
134	    }
135	}
136	
137	/// Web-aware `char`: the escaped-width counterpart of `doc::char`.
138	pub(crate) fn w_char(c: char) -> Doc {
139	    if hl_on() {
140	        let mut buf = [0u8; 4];
141	        sized_text(char_charge(c), c.encode_utf8(&mut buf))
142	    } else {
143	        char(c)
144	    }
145	}
146	
147	// ── glyph wrappers (identity in batch mode) ──────────────────────────────────
148	
149	/// A keyword token (`rule`, `modulo`, `functions:`, …) — `hl_keyword`.
150	pub(crate) fn hl_kw(s: &str) -> Doc {
151	    if hl_on() {
152	        annot("hl_keyword", w_text(s))
153	    } else {
154	        text(s)
155	    }
156	}
157	
158	/// An operator glyph given as a single char (`=`, `@`, `.`, `(`, `)`, `<`, …) —
159	/// `hl_operator`.
160	pub(crate) fn hl_op_char(c: char) -> Doc {
161	    if hl_on() {
162	        annot("hl_operator", w_char(c))
163	    } else {
164	        char(c)
165	    }
166	}
167	
168	/// An operator glyph given as text (`--[`, `]->`, `-->`, `∀ `, `⇒`, …) —
169	/// `hl_operator`. `]->` / `-->` carry a `>` and are laid out at their escaped
170	/// width (6 columns) in web mode.
171	pub(crate) fn hl_op_text(s: &str) -> Doc {
172	    if hl_on() {
173	        annot("hl_operator", w_text(s))
174	    } else {
175	        text(s)
176	    }
177	}
178	
179	/// A comment line/block (`// safety formula`, `/* … */`) — `hl_comment`.
180	pub(crate) fn hl_comment(s: &str) -> Doc {
181	    if hl_on() {
182	        annot("hl_comment", w_text(s))
183	    } else {
184	        text(s)
185	    }
186	}
187	
188	/// Wrap an already-built sub-document in a span of `class` (used for the
189	/// multi-line variants / expanded-formula comment blocks, whose interior keeps
190	/// its own nested keyword/operator spans).
191	pub(crate) fn hl_wrap(class: &str, d: Doc) -> Doc {
192	    if hl_on() {
193	        annot(class, d)
194	    } else {
195	        d
196	    }
197	}
198	
199	// ── the escape + span-expansion pass ─────────────────────────────────────────
200	
201	/// Entity-escape producer text (`& < > " '`, identical to the producers-clean
202	/// `escape_text`) AND expand the zero-width span sentinels into `<span
203	/// class="hl_…">` / `</span>`, in one pass. Leading indent spaces are left raw
204	/// (the producers postprocess turns them into `&nbsp;`); non-ASCII passes raw.
205	fn escape_and_expand(s: &str) -> String {
206	    let mut out = String::with_capacity(s.len() + s.len() / 8 + 16);
207	    let mut it = s.chars();
208	    while let Some(c) = it.next() {
209	        match c {
210	            M_OPEN => {
211	                out.push_str("<span class=\"");
212	                for cc in it.by_ref() {
213	                    if cc == M_SEP {
214	                        break;
215	                    }
216	                    out.push(cc);
217	                }
218	                out.push_str("\">");
219	            }
220	            M_CLOSE => out.push_str("</span>"),
221	            '&' => out.push_str("&amp;"),
222	            '<' => out.push_str("&lt;"),
223	            '>' => out.push_str("&gt;"),
224	            '"' => out.push_str("&quot;"),
225	            '\'' => out.push_str("&#39;"),
226	            _ => out.push(c),
227	        }
228	    }
229	    out
230	}
231	
232	/// Build a styled doc (web mode ON) and render it to an escaped, span-injected
233	/// HTML fragment body at web params. The rendered logical lines carry raw
234	/// leading spaces (postprocessed downstream) and one `\n` per line.
235	fn html_render(build: impl FnOnce() -> Doc) -> String {
236	    let _g = HlGuard::on();
237	    let doc = build();
238	    escape_and_expand(&render_with(WEB_WIDTH, WEB_RIBBON, &doc))
239	}
240	
241	// ── block render entry points ────────────────────────────────────────────────
242	
243	/// The `Signature` message-pane body: `builtins:` / `functions:` / `equations:`
244	/// with NO batch header comment.
245	pub fn render_signature_body(sig: &Signature) -> String {
246	    html_render(|| signature::web_block_doc(sig))
247	}
248	
249	/// One BARE rule (header + body only, no variants comment) — the
250	/// construction/deconstruction message-pane form.
251	pub fn render_rule_bare(r: &Rule) -> String {
252	    html_render(|| rule::core_doc(r))
253	}
254	
255	/// One FULL rule block (header + body + blank + variants comment) — the MSR
256	/// rules-pane form.
257	pub fn render_rule_block(r: &Rule, variants: Option<&AcVariants>) -> String {
258	    html_render(|| rule::block_doc(r, variants))
259	}
260	
261	/// One restriction block (statement, `// safety formula`, expanded-formula
262	/// comment) — the rules-pane restrictions form.
263	pub fn render_restriction(r: &Restriction) -> String {
264	    html_render(|| lemma::restriction_doc(r))
265	}
266	
267	/// One formula in bare (top-level) position at web params — for source views
268	/// and lemma statements (UNVALIDATED: no formula-only web capture; reuses the
269	/// restriction-validated operator spans).
270	pub fn render_formula(f: &crate::ast::Formula) -> String {
271	    html_render(|| formula::doc(f))
272	}
273	
274	// ── section-body assemblers ──────────────────────────────────────────────────
275	
276	/// A `Construction Rules` / `Deconstruction Rules` message-pane body: BARE
277	/// rules joined by one blank line.
278	pub fn render_bare_rules_body(rules: &[Rule]) -> String {
279	    rules
280	        .iter()
281	        .map(render_rule_bare)
282	        .collect::<Vec<_>>()
283	        .join("\n\n")
284	}
285	
286	/// The `Multiset Rewriting Rules` rules-pane body: FULL rule blocks joined by
287	/// TWO blank lines after a `modulo AC` rule and ZERO after a `modulo E` rule
288	/// (corpus: 164 AC→2 / 942 E→0), no trailing.
289	pub fn render_msr_body(rules: &[(Rule, Option<AcVariants>)]) -> String {
290	    let mut out = String::new();
291	    for (i, (r, v)) in rules.iter().enumerate() {
292	        if i > 0 {
293	            let prev = &rules[i - 1].0;
294	            out.push_str(if prev.modulo.as_deref() == Some("AC") {
295	                "\n\n\n"
296	            } else {
297	                "\n"
298	            });
299	        }
300	        out.push_str(&render_rule_block(r, v.as_ref()));
301	    }
302	    out
303	}
304	
305	/// The `Restrictions of the Set of Traces` rules-pane body: restriction blocks
306	/// joined by one blank line.
307	pub fn render_restrictions_body(restrictions: &[Restriction]) -> String {
308	    restrictions
309	        .iter()
310	        .map(render_restriction)
311	        .collect::<Vec<_>>()
312	        .join("\n\n")
313	}
314	
315	#[cfg(test)]
316	mod tests {
317	    use super::*;
318	    use crate::ast::{BinOp, Fact, Rule, SortHint, Term, VarSpec};
319	
320	    /// Temporarily install a doctored per-character charge; returns the previous
321	    /// one so the caller can restore it.
322	    fn set_charge(f: fn(char) -> usize) -> fn(char) -> usize {
323	        CHARGE.with(|k| k.replace(f))
324	    }
325	
326	    /// The blocker witness `c_mult`: a bare rule whose body is 66 GLYPHS but 69
327	    /// ESCAPED columns (the single `>` in `]->` charges 4). Captured as a WRAPPED
328	    /// three-row body (BP_IBS_4 / DH2_original; census in QUERIES.log R7).
329	    fn c_mult_rule() -> Rule {
330	        let v = |n: &str, i: u64| {
331	            Term::Var(VarSpec { name: n.into(), idx: i, sort: SortHint::Untagged, typ: None })
332	        };
333	        let m = Term::BinOp(BinOp::Mult, Box::new(v("x", 0)), Box::new(v("x", 1)));
334	        let ku = |a: Vec<Term>| Fact {
335	            persistent: true,
336	            name: "KU".into(),
337	            args: a,
338	            annotations: vec![],
339	        };
340	        Rule {
341	            name: "c_mult".into(),
342	            modulo: Some("AC".into()),
343	            attributes: vec![],
344	            premises: vec![ku(vec![v("x", 0)]), ku(vec![v("x", 1)])],
345	            actions: vec![ku(vec![m.clone()])],
346	            conclusions: vec![ku(vec![m])],
347	            loop_breakers: vec![],
348	        }
349	    }
350	
351	    #[test]
352	    fn escaped_char_width_matches_the_escaper() {
353	        // Every charge equals the byte length its char expands to in
354	        // `escape_and_expand`.
355	        assert_eq!(escaped_char_width('<'), "&lt;".len());
356	        assert_eq!(escaped_char_width('>'), "&gt;".len());
357	        assert_eq!(escaped_char_width('&'), "&amp;".len());
358	        assert_eq!(escaped_char_width('"'), "&quot;".len());
359	        assert_eq!(escaped_char_width('\''), "&#39;".len());
360	        assert_eq!(escaped_char_width('x'), 1);
361	        assert_eq!(escaped_char_width('\u{2200}'), 1); // ∀ passes raw
362	    }
363	
364	    #[test]
365	    fn escaped_charging_is_load_bearing() {
366	        // Under the production ESCAPED charge the content-66 body wraps to a
367	        // header + three rows (4 lines), matching the captures. Doctoring the
368	        // charge to glyph width (the mutation) drops the escaped 69 to 66 <=
369	        // ribbon 67, so the body stays on one line (2 lines) — a DIFFERENT byte
370	        // output. Hence the byte gate genuinely rides on the escaped charging.
371	        let r = c_mult_rule();
372	        let real = render_rule_bare(&r);
373	        assert_eq!(real.lines().count(), 4, "escaped charge wraps the body");
374	
375	        let prev = set_charge(|_| 1); // doctor: charge every char its glyph width
376	        let mutant = render_rule_bare(&r);
377	        set_charge(prev);
378	        assert_eq!(mutant.lines().count(), 2, "glyph charge keeps the body one line");
379	        assert_ne!(real, mutant, "doctoring the charge changes the rendered bytes");
380	    }
381	}
