1	//! Open-side adapter for the vendored `pretty_clean` clean-room renderer (R1).
2	//!
3	//! This is workspace-authored glue: it only translates live
4	//! `tamarin_parser::ast` / `tamarin_term` values into the clean crate's own AST
5	//! subset and forwards to `pretty_clean`. No rendering logic lives here — every
6	//! byte of output comes out of the clean crate.
7	
8	use crate::pretty_clean::ast as c;
9	use tamarin_parser::ast as p;
10	use tamarin_term::maude_sig::MaudeSig;
11	
12	// ── term: parser AST -> clean AST (1:1 structural, the surfaces are identical) ─
13	
14	/// Structural conversion of a parser-AST term into the clean-AST term.
15	pub fn term(t: &p::Term) -> c::Term {
16	    match t {
17	        p::Term::Var(v) => c::Term::Var(varspec(v)),
18	        p::Term::PubLit(s) => c::Term::PubLit(s.clone()),
19	        p::Term::FreshLit(s) => c::Term::FreshLit(s.clone()),
20	        p::Term::NatLit(s) => c::Term::NatLit(s.clone()),
21	        p::Term::Number(n) => c::Term::Number(*n),
22	        p::Term::NumberOne => c::Term::NumberOne,
23	        p::Term::NatOne => c::Term::NatOne,
24	        p::Term::DhNeutral => c::Term::DhNeutral,
25	        p::Term::App(f, args) => c::Term::App(f.clone(), args.iter().map(term).collect()),
26	        p::Term::AlgApp(n, a, b) => {
27	            c::Term::AlgApp(n.clone(), Box::new(term(a)), Box::new(term(b)))
28	        }
29	        p::Term::Pair(elems) => c::Term::Pair(elems.iter().map(term).collect()),
30	        p::Term::Diff(a, b) => c::Term::Diff(Box::new(term(a)), Box::new(term(b))),
31	        p::Term::BinOp(op, a, b) => {
32	            c::Term::BinOp(binop(*op), Box::new(term(a)), Box::new(term(b)))
33	        }
34	        p::Term::PatMatch(inner) => c::Term::PatMatch(Box::new(term(inner))),
35	    }
36	}
37	
38	fn varspec(v: &p::VarSpec) -> c::VarSpec {
39	    c::VarSpec {
40	        name: v.name.clone(),
41	        idx: v.idx,
42	        sort: sort(v.sort),
43	        typ: v.typ.clone(),
44	    }
45	}
46	
47	fn sort(s: p::SortHint) -> c::SortHint {
48	    match s {
49	        p::SortHint::Msg => c::SortHint::Msg,
50	        p::SortHint::Pub => c::SortHint::Pub,
51	        p::SortHint::Fresh => c::SortHint::Fresh,
52	        p::SortHint::Node => c::SortHint::Node,
53	        p::SortHint::Nat => c::SortHint::Nat,
54	        p::SortHint::Suffix(x) => c::SortHint::Suffix(suffix(x)),
55	        p::SortHint::Untagged => c::SortHint::Untagged,
56	    }
57	}
58	
59	fn suffix(s: p::SuffixSort) -> c::SuffixSort {
60	    match s {
61	        p::SuffixSort::Msg => c::SuffixSort::Msg,
62	        p::SuffixSort::Pub => c::SuffixSort::Pub,
63	        p::SuffixSort::Fresh => c::SuffixSort::Fresh,
64	        p::SuffixSort::Node => c::SuffixSort::Node,
65	        p::SuffixSort::Nat => c::SuffixSort::Nat,
66	    }
67	}
68	
69	fn binop(op: p::BinOp) -> c::BinOp {
70	    match op {
71	        p::BinOp::Exp => c::BinOp::Exp,
72	        p::BinOp::Mult => c::BinOp::Mult,
73	        p::BinOp::Union => c::BinOp::Union,
74	        p::BinOp::Xor => c::BinOp::Xor,
75	        p::BinOp::NatPlus => c::BinOp::NatPlus,
76	    }
77	}
78	
79	// ── signature block: closed MaudeSig -> clean Signature ───────────────────────
80	
81	/// Build the clean-AST `Signature` from the CLOSED `MaudeSig`.
82	///
83	/// The clean crate performs its own observable closure (it always re-adds the
84	/// base pairing symbols/equations and then dedups + sorts). We therefore hand
85	/// it the enabled line-builtins (for the `builtins:` line only — those five add
86	/// no function/equation entries in the clean expander) plus the fully-closed
87	/// `st_fun_syms` / `st_rules` as "user" declarations; the clean crate's dedup
88	/// merges the duplicated base pairing entries, so the merged set equals the
89	/// ported `render_fun_syms` / `render_equations` input.
90	pub fn signature(sig: &MaudeSig) -> c::Signature {
91	    use tamarin_term::function_symbols::{Constructability, Privacy};
92	
93	    let mut builtins: Vec<String> = Vec::new();
94	    if sig.enable_dh {
95	        builtins.push("diffie-hellman".into());
96	    }
97	    if sig.enable_bp {
98	        builtins.push("bilinear-pairing".into());
99	    }
100	    if sig.enable_mset {
101	        builtins.push("multiset".into());
102	    }
103	    if sig.enable_nat {
104	        builtins.push("natural-numbers".into());
105	    }
106	    if sig.enable_xor {
107	        builtins.push("xor".into());
108	    }
109	    // Input normalization (not clean-crate logic): the clean expander always
110	    // re-adds the base pairing symbols, defaulting `fst`/`snd` to CONSTRUCTORS
111	    // unless the declared builtins carry `dest-pairing`. When the closed
112	    // signature holds them as DESTRUCTORS (`fst/1[destructor]`), signal that to
113	    // the clean expander so its base pairing matches and dedups against the
114	    // closed symbols instead of duplicating them. `dest-pairing` is not a
115	    // line-builtin, so it adds no `builtins:` entry.
116	    let dest_pairing = sig.st_fun_syms.iter().any(|s| {
117	        s.arity == 1
118	            && matches!(s.constructability, Constructability::Destructor)
119	            && matches!(&*String::from_utf8_lossy(s.name), "fst" | "snd")
120	    });
121	    if dest_pairing {
122	        builtins.push("dest-pairing".into());
123	    }
124	
125	    let functions: Vec<c::FunctionDecl> = sig
126	        .st_fun_syms
127	        .iter()
128	        .map(|s| c::FunctionDecl {
129	            name: String::from_utf8_lossy(s.name).into_owned(),
130	            arity: s.arity,
131	            private: matches!(s.privacy, Privacy::Private),
132	            destructor: matches!(s.constructability, Constructability::Destructor),
133	        })
134	        .collect();
135	
136	    let equations: Vec<c::Equation> = sig
137	        .st_rules
138	        .iter()
139	        .map(|r| c::Equation {
140	            lhs: term(&crate::pretty_theory::lnterm_to_parser(&r.lhs)),
141	            rhs: term(&crate::pretty_theory::lnterm_to_parser(&r.rhs.term)),
142	        })
143	        .collect();
144	
145	    c::Signature {
146	        builtins,
147	        functions,
148	        equations,
149	        convergent: sig.eq_convergent,
150	    }
151	}
152	
153	/// The full signature section (header comment + blank line + `builtins:` /
154	/// `functions:` / `equations:` lines) with the trailing newline the theory
155	/// echo expects, rendered entirely by the clean crate. Drop-in for the ported
156	/// `render_signature` call site including the `// Function signature …` header
157	/// (the clean `render_signature_block` emits that header itself).
158	pub fn signature_section(sig: &MaudeSig) -> String {
159	    let mut s = crate::pretty_clean::render_signature_block(&signature(sig));
160	    s.push('\n');
161	    s
162	}
163	
164	// ── facts / rules: parser AST -> clean AST (1:1 structural value translation) ─
165	
166	/// Structural conversion of a parser-AST fact into the clean-AST fact. The
167	/// term/annotation transforms (arity-1 fold, AC canonicalisation, macro
168	/// expansion) are performed PORTED-side before this call; here we only re-shape
169	/// the value.
170	pub fn fact(f: &p::Fact) -> c::Fact {
171	    c::Fact {
172	        persistent: f.persistent,
173	        name: f.name.clone(),
174	        args: f.args.iter().map(term).collect(),
175	        annotations: f.annotations.iter().map(fact_annotation).collect(),
176	    }
177	}
178	
179	fn fact_annotation(a: &p::FactAnnotation) -> c::FactAnnotation {
180	    match a {
181	        p::FactAnnotation::SolveFirst => c::FactAnnotation::SolveFirst,
182	        p::FactAnnotation::SolveLast => c::FactAnnotation::SolveLast,
183	        p::FactAnnotation::NoSources => c::FactAnnotation::NoSources,
184	    }
185	}
186	
187	/// Structural conversion of one rule attribute. The `color` value is
188	/// `#`-stripped and lowercased here (the closed-theory representation the
189	/// ported `rgbToHex` produces), a value normalisation only — the clean crate
190	/// re-attaches the `#` and renders the canonical attribute order/selection.
191	fn rule_attr(a: &p::RuleAttr) -> c::RuleAttr {
192	    match a {
193	        p::RuleAttr::Color(hex) => {
194	            c::RuleAttr::Color(hex.trim_start_matches('#').to_lowercase())
195	        }
196	        p::RuleAttr::NoDerivCheck => c::RuleAttr::NoDerivCheck,
197	        p::RuleAttr::Role(r) => c::RuleAttr::Role(r.clone()),
198	        p::RuleAttr::IsSapicRule => c::RuleAttr::IsSapicRule,
199	        p::RuleAttr::Process(s) => c::RuleAttr::Process(s.clone()),
200	        p::RuleAttr::External(k, v) => c::RuleAttr::External(k.clone(), v.clone()),
201	    }
202	}
203	
204	fn clean_rule(
205	    name: &str,
206	    modulo: Option<&str>,
207	    attrs: &[p::RuleAttr],
208	    prems: &[p::Fact],
209	    acts: &[p::Fact],
210	    concs: &[p::Fact],
211	    loop_breakers: &[usize],
212	) -> c::Rule {
213	    c::Rule {
214	        name: name.to_string(),
215	        modulo: modulo.map(str::to_string),
216	        attributes: attrs.iter().map(rule_attr).collect(),
217	        premises: prems.iter().map(fact).collect(),
218	        actions: acts.iter().map(fact).collect(),
219	        conclusions: concs.iter().map(fact).collect(),
220	        loop_breakers: loop_breakers.to_vec(),
221	    }
222	}
223	
224	/// Pre-computed AC-variant inputs (all parser values; every transform stays
225	/// ported). The clean crate consumes these to render the `variants (modulo
226	/// AC)` comment.
227	pub struct AcVariantsInput<'a> {
228	    pub ac_attrs: &'a [p::RuleAttr],
229	    pub ac_prems: &'a [p::Fact],
230	    pub ac_acts: &'a [p::Fact],
231	    pub ac_concs: &'a [p::Fact],
232	    pub ac_loop_breakers: &'a [usize],
233	    /// Numbered substitution groups, each a `(domain-var, range-term)` list;
234	    /// empty (the outer Vec) means no `variants (modulo AC)` sub-block.
235	    pub substitutions: Vec<Vec<(p::Term, p::Term)>>,
236	}
237	
238	/// One whole rule block, rendered by the clean crate. `name`/`e_*` describe the
239	/// modulo-E rule (facts already fully transformed ported-side);
240	/// `outer_loop_breakers` is the (already gated) outer loop-breaker index list;
241	/// `variants` is `None` for the trivial-AC-variant one-liner, else the
242	/// pre-computed AC-variant comment inputs. Drop-in for the ported `render_rule`
243	/// theory-body call.
244	pub fn rule_section(
245	    name: &str,
246	    attrs: &[p::RuleAttr],
247	    e_prems: &[p::Fact],
248	    e_acts: &[p::Fact],
249	    e_concs: &[p::Fact],
250	    outer_loop_breakers: &[usize],
251	    variants: Option<AcVariantsInput>,
252	) -> String {
253	    let e_rule = clean_rule(
254	        name, Some("E"), attrs, e_prems, e_acts, e_concs, outer_loop_breakers,
255	    );
256	    let ac = variants.map(|v| c::AcVariants {
257	        ac_rule: clean_rule(
258	            name, Some("AC"), v.ac_attrs, v.ac_prems, v.ac_acts, v.ac_concs,
259	            v.ac_loop_breakers,
260	        ),
261	        substitutions: v
262	            .substitutions
263	            .iter()
264	            .map(|group| group.iter().map(|(l, r)| (term(l), term(r))).collect())
265	            .collect(),
266	    });
267	    crate::pretty_clean::render_rule(&e_rule, ac.as_ref())
268	}
269	
270	// ── formulas: parser AST -> clean AST (1:1 structural value translation) ──────
271	
272	/// Structural conversion of a parser-AST formula into the clean-AST formula.
273	/// Predicate expansion, arity-1 folding and AC canonicalisation are performed
274	/// PORTED-side before this call; here we only re-shape the value.
275	pub fn formula(f: &p::Formula) -> c::Formula {
276	    match f {
277	        p::Formula::False => c::Formula::False,
278	        p::Formula::True => c::Formula::True,
279	        p::Formula::Atom(a) => c::Formula::Atom(atom(a)),
280	        p::Formula::Not(g) => c::Formula::Not(Box::new(formula(g))),
281	        p::Formula::And(l, r) => c::Formula::And(Box::new(formula(l)), Box::new(formula(r))),
282	        p::Formula::Or(l, r) => c::Formula::Or(Box::new(formula(l)), Box::new(formula(r))),
283	        p::Formula::Implies(l, r) => {
284	            c::Formula::Implies(Box::new(formula(l)), Box::new(formula(r)))
285	        }
286	        p::Formula::Iff(l, r) => c::Formula::Iff(Box::new(formula(l)), Box::new(formula(r))),
287	        p::Formula::Forall(vs, b) => {
288	            c::Formula::Forall(vs.iter().map(varspec).collect(), Box::new(formula(b)))
289	        }
290	        p::Formula::Exists(vs, b) => {
291	            c::Formula::Exists(vs.iter().map(varspec).collect(), Box::new(formula(b)))
292	        }
293	    }
294	}
295	
296	fn atom(a: &p::Atom) -> c::Atom {
297	    match a {
298	        p::Atom::Eq(l, r) => c::Atom::Eq(term(l), term(r)),
299	        p::Atom::Less(l, r) => c::Atom::Less(term(l), term(r)),
300	        p::Atom::LessMset(l, r) => c::Atom::LessMset(term(l), term(r)),
301	        p::Atom::Subterm(l, r) => c::Atom::Subterm(term(l), term(r)),
302	        p::Atom::Action(f, tp) => c::Atom::Action(fact(f), term(tp)),
303	        p::Atom::Last(tp) => c::Atom::Last(term(tp)),
304	        p::Atom::Pred(f) => c::Atom::Pred(fact(f)),
305	    }
306	}
307	
308	// ── restriction block ─────────────────────────────────────────────────────────
309	
310	/// One whole restriction block, rendered by the clean crate. `statement` is the
311	/// restriction formula AS WRITTEN (macro-form) shown on the top line;
312	/// `expanded` is the macro/predicate-EXPANDED formula shown in the
313	/// `/* expanded formula: … */` comment. Both are supplied already fully
314	/// transformed and sort-resolved (predicate expansion, arity-1 fold, AC
315	/// canonicalisation, sort resolution stay PORTED — the expanded formula is a
316	/// caller-supplied INPUT, never derived here). Without macros the two are
317	/// equal. Drop-in for the ported `render_parsed_restriction` theory-body call.
318	pub fn restriction_section(name: &str, statement: &p::Formula, expanded: &p::Formula) -> String {
319	    let r = c::Restriction {
320	        name: name.to_string(),
321	        formula: formula(statement),
322	        expanded: formula(expanded),
323	    };
324	    crate::pretty_clean::render_restriction(&r)
325	}
326	
327	// ── lemma block ───────────────────────────────────────────────────────────────
328	
329	fn trace_quantifier(q: &p::TraceQuantifier) -> c::TraceQuantifier {
330	    match q {
331	        p::TraceQuantifier::AllTraces => c::TraceQuantifier::AllTraces,
332	        p::TraceQuantifier::ExistsTrace => c::TraceQuantifier::ExistsTrace,
333	    }
334	}
335	
336	/// Map one parser lemma attribute to the clean AST. The `Heuristic` value is
337	/// supplied ALREADY oracle-expanded (the file-dependent `prettyGoalRankings`
338	/// transform stays ported). Attributes the clean crate does not model
339	/// (`diff_reuse`, `output=`, `left`, `right`, `hint`) have no corpus witness in
340	/// the no-prove echo (see clean SPEC UNOBSERVABLE register) and are dropped.
341	fn lemma_attr(a: &p::LemmaAttr) -> Option<c::LemmaAttr> {
342	    match a {
343	        p::LemmaAttr::Sources => Some(c::LemmaAttr::Sources),
344	        p::LemmaAttr::Reuse => Some(c::LemmaAttr::Reuse),
345	        p::LemmaAttr::UseInduction => Some(c::LemmaAttr::UseInduction),
346	        p::LemmaAttr::HideLemma(s) => Some(c::LemmaAttr::HideLemma(s.clone())),
347	        p::LemmaAttr::Heuristic(v) => Some(c::LemmaAttr::Heuristic(v.clone())),
348	        _ => None,
349	    }
350	}
351	
352	/// Pre-computed guarded-formula comment body (from the ported guarded
353	/// transform). `Formula` carries the quoted multi-line guarded block verbatim;
354	/// `Failed` carries the un-indented failure body (the clean crate re-indents it
355	/// two columns under its own header).
356	pub enum GuardedInput {
357	    Formula(String),
358	    Failed(String),
359	}
360	
361	/// One whole lemma block, rendered by the clean crate. `attrs` carries any
362	/// `Heuristic` value ALREADY oracle-expanded; `formula` is the fully
363	/// transformed lemma statement formula; `guarded` is the pre-computed guarded
364	/// comment body (`None` skips the comment); `proof` is the embedded proof tail
365	/// (`None` renders `by sorry`).
366	pub fn lemma_section(
367	    name: &str,
368	    attrs: &[p::LemmaAttr],
369	    quant: &p::TraceQuantifier,
370	    f: &p::Formula,
371	    guarded: Option<GuardedInput>,
372	    proof: Option<&str>,
373	) -> String {
374	    let lemma = c::Lemma {
375	        name: name.to_string(),
376	        attributes: attrs.iter().filter_map(lemma_attr).collect(),
377	        trace_quantifier: trace_quantifier(quant),
378	        formula: formula(f),
379	        proof: proof.map(str::to_string),
380	    };
381	    let g = guarded.map(|gi| match gi {
382	        GuardedInput::Formula(s) => c::Guarded::Formula(s),
383	        GuardedInput::Failed(s) => c::Guarded::Failed(s),
384	    });
385	    crate::pretty_clean::render_lemma(&lemma, g.as_ref())
386	}
387	
388	// ── macros block ──────────────────────────────────────────────────────────────
389	
390	/// Structural conversion of one parser-AST macro into the clean-AST macro. The
391	/// head/body terms are re-shaped 1:1 (parameters become `Var` terms); no
392	/// transform lives here.
393	fn macro_conv(m: &p::Macro) -> c::Macro {
394	    c::Macro {
395	        name: m.name.clone(),
396	        params: m.args.iter().map(|v| c::Term::Var(varspec(v))).collect(),
397	        body: term(&m.body),
398	    }
399	}
400	
401	/// The whole `macros:` block, rendered by the clean crate (the always-break
402	/// vcat layout). Drop-in for the ported `render_parsed_macros` theory-body call.
403	pub fn macros_section(macros: &[p::Macro]) -> String {
404	    let ms: Vec<c::Macro> = macros.iter().map(macro_conv).collect();
405	    crate::pretty_clean::render_macros(&ms)
406	}
407	
408	// ── predicates block ──────────────────────────────────────────────────────────
409	
410	/// A contiguous run of `predicate:` declarations, rendered by the clean crate
411	/// (one `predicate: <fact><=><formula>` per predicate, blank-line separated).
412	/// Each item is `(predicate-fact NAME, formal PARAMS, BODY formula)`; the body
413	/// is supplied ALREADY arity-1 folded and sort-resolved (transforms stay
414	/// PORTED). Drop-in for the ported per-predicate `render_predicate` join.
415	pub fn predicates_section(items: &[(String, Vec<p::VarSpec>, p::Formula)]) -> String {
416	    let preds: Vec<c::Predicate> = items
417	        .iter()
418	        .map(|(name, params, body)| c::Predicate {
419	            name: name.clone(),
420	            params: params.iter().map(varspec).collect(),
421	            body: formula(body),
422	        })
423	        .collect();
424	    crate::pretty_clean::render_predicates(&preds)
425	}
