//! Open-side adapter for the vendored `pretty_clean` clean-room renderer (R1).
//!
//! This is workspace-authored glue: it only translates live
//! `tamarin_parser::ast` / `tamarin_term` values into the clean crate's own AST
//! subset and forwards to `pretty_clean`. No rendering logic lives here — every
//! byte of output comes out of the clean crate.

use crate::pretty_clean::ast as c;
use tamarin_parser::ast as p;
use tamarin_term::maude_sig::MaudeSig;

// ── term: parser AST -> clean AST (1:1 structural, the surfaces are identical) ─

/// Structural conversion of a parser-AST term into the clean-AST term.
pub fn term(t: &p::Term) -> c::Term {
    match t {
        p::Term::Var(v) => c::Term::Var(varspec(v)),
        p::Term::PubLit(s) => c::Term::PubLit(s.clone()),
        p::Term::FreshLit(s) => c::Term::FreshLit(s.clone()),
        p::Term::NatLit(s) => c::Term::NatLit(s.clone()),
        p::Term::Number(n) => c::Term::Number(*n),
        p::Term::NumberOne => c::Term::NumberOne,
        p::Term::NatOne => c::Term::NatOne,
        p::Term::DhNeutral => c::Term::DhNeutral,
        p::Term::App(f, args) => c::Term::App(f.clone(), args.iter().map(term).collect()),
        p::Term::AlgApp(n, a, b) => {
            c::Term::AlgApp(n.clone(), Box::new(term(a)), Box::new(term(b)))
        }
        p::Term::Pair(elems) => c::Term::Pair(elems.iter().map(term).collect()),
        p::Term::Diff(a, b) => c::Term::Diff(Box::new(term(a)), Box::new(term(b))),
        p::Term::BinOp(op, a, b) => {
            c::Term::BinOp(binop(*op), Box::new(term(a)), Box::new(term(b)))
        }
        p::Term::PatMatch(inner) => c::Term::PatMatch(Box::new(term(inner))),
    }
}

fn varspec(v: &p::VarSpec) -> c::VarSpec {
    c::VarSpec {
        name: v.name.clone(),
        idx: v.idx,
        sort: sort(v.sort),
        typ: v.typ.clone(),
    }
}

fn sort(s: p::SortHint) -> c::SortHint {
    match s {
        p::SortHint::Msg => c::SortHint::Msg,
        p::SortHint::Pub => c::SortHint::Pub,
        p::SortHint::Fresh => c::SortHint::Fresh,
        p::SortHint::Node => c::SortHint::Node,
        p::SortHint::Nat => c::SortHint::Nat,
        p::SortHint::Suffix(x) => c::SortHint::Suffix(suffix(x)),
        p::SortHint::Untagged => c::SortHint::Untagged,
    }
}

fn suffix(s: p::SuffixSort) -> c::SuffixSort {
    match s {
        p::SuffixSort::Msg => c::SuffixSort::Msg,
        p::SuffixSort::Pub => c::SuffixSort::Pub,
        p::SuffixSort::Fresh => c::SuffixSort::Fresh,
        p::SuffixSort::Node => c::SuffixSort::Node,
        p::SuffixSort::Nat => c::SuffixSort::Nat,
    }
}

fn binop(op: p::BinOp) -> c::BinOp {
    match op {
        p::BinOp::Exp => c::BinOp::Exp,
        p::BinOp::Mult => c::BinOp::Mult,
        p::BinOp::Union => c::BinOp::Union,
        p::BinOp::Xor => c::BinOp::Xor,
        p::BinOp::NatPlus => c::BinOp::NatPlus,
    }
}

// ── signature block: closed MaudeSig -> clean Signature ───────────────────────

/// Build the clean-AST `Signature` from the CLOSED `MaudeSig`.
///
/// The clean crate performs its own observable closure (it always re-adds the
/// base pairing symbols/equations and then dedups + sorts). We therefore hand
/// it the enabled line-builtins (for the `builtins:` line only — those five add
/// no function/equation entries in the clean expander) plus the fully-closed
/// `st_fun_syms` / `st_rules` as "user" declarations; the clean crate's dedup
/// merges the duplicated base pairing entries, so the merged set equals the
/// ported `render_fun_syms` / `render_equations` input.
pub fn signature(sig: &MaudeSig) -> c::Signature {
    use tamarin_term::function_symbols::{Constructability, Privacy};

    let mut builtins: Vec<String> = Vec::new();
    if sig.enable_dh {
        builtins.push("diffie-hellman".into());
    }
    if sig.enable_bp {
        builtins.push("bilinear-pairing".into());
    }
    if sig.enable_mset {
        builtins.push("multiset".into());
    }
    if sig.enable_nat {
        builtins.push("natural-numbers".into());
    }
    if sig.enable_xor {
        builtins.push("xor".into());
    }
    // Input normalization (not clean-crate logic): the clean expander always
    // re-adds the base pairing symbols, defaulting `fst`/`snd` to CONSTRUCTORS
    // unless the declared builtins carry `dest-pairing`. When the closed
    // signature holds them as DESTRUCTORS (`fst/1[destructor]`), signal that to
    // the clean expander so its base pairing matches and dedups against the
    // closed symbols instead of duplicating them. `dest-pairing` is not a
    // line-builtin, so it adds no `builtins:` entry.
    let dest_pairing = sig.st_fun_syms.iter().any(|s| {
        s.arity == 1
            && matches!(s.constructability, Constructability::Destructor)
            && matches!(&*String::from_utf8_lossy(s.name), "fst" | "snd")
    });
    if dest_pairing {
        builtins.push("dest-pairing".into());
    }

    let functions: Vec<c::FunctionDecl> = sig
        .st_fun_syms
        .iter()
        .map(|s| c::FunctionDecl {
            name: String::from_utf8_lossy(s.name).into_owned(),
            arity: s.arity,
            private: matches!(s.privacy, Privacy::Private),
            destructor: matches!(s.constructability, Constructability::Destructor),
        })
        .collect();

    let equations: Vec<c::Equation> = sig
        .st_rules
        .iter()
        .map(|r| c::Equation {
            lhs: term(&crate::pretty_theory::lnterm_to_parser(&r.lhs)),
            rhs: term(&crate::pretty_theory::lnterm_to_parser(&r.rhs.term)),
        })
        .collect();

    c::Signature {
        builtins,
        functions,
        equations,
        convergent: sig.eq_convergent,
    }
}

/// The full signature section (header comment + blank line + `builtins:` /
/// `functions:` / `equations:` lines) with the trailing newline the theory
/// echo expects, rendered entirely by the clean crate. Drop-in for the ported
/// `render_signature` call site including the `// Function signature …` header
/// (the clean `render_signature_block` emits that header itself).
pub fn signature_section(sig: &MaudeSig) -> String {
    let mut s = crate::pretty_clean::render_signature_block(&signature(sig));
    s.push('\n');
    s
}

// ── facts / rules: parser AST -> clean AST (1:1 structural value translation) ─

/// Structural conversion of a parser-AST fact into the clean-AST fact. The
/// term/annotation transforms (arity-1 fold, AC canonicalisation, macro
/// expansion) are performed PORTED-side before this call; here we only re-shape
/// the value.
pub fn fact(f: &p::Fact) -> c::Fact {
    c::Fact {
        persistent: f.persistent,
        name: f.name.clone(),
        args: f.args.iter().map(term).collect(),
        annotations: f.annotations.iter().map(fact_annotation).collect(),
    }
}

fn fact_annotation(a: &p::FactAnnotation) -> c::FactAnnotation {
    match a {
        p::FactAnnotation::SolveFirst => c::FactAnnotation::SolveFirst,
        p::FactAnnotation::SolveLast => c::FactAnnotation::SolveLast,
        p::FactAnnotation::NoSources => c::FactAnnotation::NoSources,
    }
}

/// Structural conversion of one rule attribute. The `color` value is
/// `#`-stripped and lowercased here (the closed-theory representation the
/// ported `rgbToHex` produces), a value normalisation only — the clean crate
/// re-attaches the `#` and renders the canonical attribute order/selection.
fn rule_attr(a: &p::RuleAttr) -> c::RuleAttr {
    match a {
        p::RuleAttr::Color(hex) => {
            c::RuleAttr::Color(hex.trim_start_matches('#').to_lowercase())
        }
        p::RuleAttr::NoDerivCheck => c::RuleAttr::NoDerivCheck,
        p::RuleAttr::Role(r) => c::RuleAttr::Role(r.clone()),
        p::RuleAttr::IsSapicRule => c::RuleAttr::IsSapicRule,
        p::RuleAttr::Process(s) => c::RuleAttr::Process(s.clone()),
        p::RuleAttr::External(k, v) => c::RuleAttr::External(k.clone(), v.clone()),
    }
}

fn clean_rule(
    name: &str,
    modulo: Option<&str>,
    attrs: &[p::RuleAttr],
    prems: &[p::Fact],
    acts: &[p::Fact],
    concs: &[p::Fact],
    loop_breakers: &[usize],
) -> c::Rule {
    c::Rule {
        name: name.to_string(),
        modulo: modulo.map(str::to_string),
        attributes: attrs.iter().map(rule_attr).collect(),
        premises: prems.iter().map(fact).collect(),
        actions: acts.iter().map(fact).collect(),
        conclusions: concs.iter().map(fact).collect(),
        loop_breakers: loop_breakers.to_vec(),
    }
}

/// Pre-computed AC-variant inputs (all parser values; every transform stays
/// ported). The clean crate consumes these to render the `variants (modulo
/// AC)` comment.
pub struct AcVariantsInput<'a> {
    pub ac_attrs: &'a [p::RuleAttr],
    pub ac_prems: &'a [p::Fact],
    pub ac_acts: &'a [p::Fact],
    pub ac_concs: &'a [p::Fact],
    pub ac_loop_breakers: &'a [usize],
    /// Numbered substitution groups, each a `(domain-var, range-term)` list;
    /// empty (the outer Vec) means no `variants (modulo AC)` sub-block.
    pub substitutions: Vec<Vec<(p::Term, p::Term)>>,
}

/// One whole rule block, rendered by the clean crate. `name`/`e_*` describe the
/// modulo-E rule (facts already fully transformed ported-side);
/// `outer_loop_breakers` is the (already gated) outer loop-breaker index list;
/// `variants` is `None` for the trivial-AC-variant one-liner, else the
/// pre-computed AC-variant comment inputs. Drop-in for the ported `render_rule`
/// theory-body call.
pub fn rule_section(
    name: &str,
    attrs: &[p::RuleAttr],
    e_prems: &[p::Fact],
    e_acts: &[p::Fact],
    e_concs: &[p::Fact],
    outer_loop_breakers: &[usize],
    variants: Option<AcVariantsInput>,
) -> String {
    let e_rule = clean_rule(
        name, Some("E"), attrs, e_prems, e_acts, e_concs, outer_loop_breakers,
    );
    let ac = variants.map(|v| c::AcVariants {
        ac_rule: clean_rule(
            name, Some("AC"), v.ac_attrs, v.ac_prems, v.ac_acts, v.ac_concs,
            v.ac_loop_breakers,
        ),
        substitutions: v
            .substitutions
            .iter()
            .map(|group| group.iter().map(|(l, r)| (term(l), term(r))).collect())
            .collect(),
    });
    crate::pretty_clean::render_rule(&e_rule, ac.as_ref())
}

// ── formulas: parser AST -> clean AST (1:1 structural value translation) ──────

/// Structural conversion of a parser-AST formula into the clean-AST formula.
/// Predicate expansion, arity-1 folding and AC canonicalisation are performed
/// PORTED-side before this call; here we only re-shape the value.
pub fn formula(f: &p::Formula) -> c::Formula {
    match f {
        p::Formula::False => c::Formula::False,
        p::Formula::True => c::Formula::True,
        p::Formula::Atom(a) => c::Formula::Atom(atom(a)),
        p::Formula::Not(g) => c::Formula::Not(Box::new(formula(g))),
        p::Formula::And(l, r) => c::Formula::And(Box::new(formula(l)), Box::new(formula(r))),
        p::Formula::Or(l, r) => c::Formula::Or(Box::new(formula(l)), Box::new(formula(r))),
        p::Formula::Implies(l, r) => {
            c::Formula::Implies(Box::new(formula(l)), Box::new(formula(r)))
        }
        p::Formula::Iff(l, r) => c::Formula::Iff(Box::new(formula(l)), Box::new(formula(r))),
        p::Formula::Forall(vs, b) => {
            c::Formula::Forall(vs.iter().map(varspec).collect(), Box::new(formula(b)))
        }
        p::Formula::Exists(vs, b) => {
            c::Formula::Exists(vs.iter().map(varspec).collect(), Box::new(formula(b)))
        }
    }
}

fn atom(a: &p::Atom) -> c::Atom {
    match a {
        p::Atom::Eq(l, r) => c::Atom::Eq(term(l), term(r)),
        p::Atom::Less(l, r) => c::Atom::Less(term(l), term(r)),
        p::Atom::LessMset(l, r) => c::Atom::LessMset(term(l), term(r)),
        p::Atom::Subterm(l, r) => c::Atom::Subterm(term(l), term(r)),
        p::Atom::Action(f, tp) => c::Atom::Action(fact(f), term(tp)),
        p::Atom::Last(tp) => c::Atom::Last(term(tp)),
        p::Atom::Pred(f) => c::Atom::Pred(fact(f)),
    }
}

// ── restriction block ─────────────────────────────────────────────────────────

/// One whole restriction block, rendered by the clean crate. `statement` is the
/// restriction formula AS WRITTEN (macro-form) shown on the top line;
/// `expanded` is the macro/predicate-EXPANDED formula shown in the
/// `/* expanded formula: … */` comment. Both are supplied already fully
/// transformed and sort-resolved (predicate expansion, arity-1 fold, AC
/// canonicalisation, sort resolution stay PORTED — the expanded formula is a
/// caller-supplied INPUT, never derived here). Without macros the two are
/// equal. Drop-in for the ported `render_parsed_restriction` theory-body call.
pub fn restriction_section(name: &str, statement: &p::Formula, expanded: &p::Formula) -> String {
    let r = c::Restriction {
        name: name.to_string(),
        formula: formula(statement),
        expanded: formula(expanded),
    };
    crate::pretty_clean::render_restriction(&r)
}

// ── lemma block ───────────────────────────────────────────────────────────────

fn trace_quantifier(q: &p::TraceQuantifier) -> c::TraceQuantifier {
    match q {
        p::TraceQuantifier::AllTraces => c::TraceQuantifier::AllTraces,
        p::TraceQuantifier::ExistsTrace => c::TraceQuantifier::ExistsTrace,
    }
}

/// Map one parser lemma attribute to the clean AST. The `Heuristic` value is
/// supplied ALREADY oracle-expanded (the file-dependent `prettyGoalRankings`
/// transform stays ported). Attributes the clean crate does not model
/// (`diff_reuse`, `output=`, `left`, `right`, `hint`) have no corpus witness in
/// the no-prove echo (see clean SPEC UNOBSERVABLE register) and are dropped.
fn lemma_attr(a: &p::LemmaAttr) -> Option<c::LemmaAttr> {
    match a {
        p::LemmaAttr::Sources => Some(c::LemmaAttr::Sources),
        p::LemmaAttr::Reuse => Some(c::LemmaAttr::Reuse),
        p::LemmaAttr::UseInduction => Some(c::LemmaAttr::UseInduction),
        p::LemmaAttr::HideLemma(s) => Some(c::LemmaAttr::HideLemma(s.clone())),
        p::LemmaAttr::Heuristic(v) => Some(c::LemmaAttr::Heuristic(v.clone())),
        _ => None,
    }
}

/// Pre-computed guarded-formula comment body (from the ported guarded
/// transform). `Formula` carries the quoted multi-line guarded block verbatim;
/// `Failed` carries the un-indented failure body (the clean crate re-indents it
/// two columns under its own header).
pub enum GuardedInput {
    Formula(String),
    Failed(String),
}

/// One whole lemma block, rendered by the clean crate. `attrs` carries any
/// `Heuristic` value ALREADY oracle-expanded; `formula` is the fully
/// transformed lemma statement formula; `guarded` is the pre-computed guarded
/// comment body (`None` skips the comment); `proof` is the embedded proof tail
/// (`None` renders `by sorry`).
pub fn lemma_section(
    name: &str,
    attrs: &[p::LemmaAttr],
    quant: &p::TraceQuantifier,
    f: &p::Formula,
    guarded: Option<GuardedInput>,
    proof: Option<&str>,
) -> String {
    let lemma = c::Lemma {
        name: name.to_string(),
        attributes: attrs.iter().filter_map(lemma_attr).collect(),
        trace_quantifier: trace_quantifier(quant),
        formula: formula(f),
        proof: proof.map(str::to_string),
    };
    let g = guarded.map(|gi| match gi {
        GuardedInput::Formula(s) => c::Guarded::Formula(s),
        GuardedInput::Failed(s) => c::Guarded::Failed(s),
    });
    crate::pretty_clean::render_lemma(&lemma, g.as_ref())
}

// ── macros block ──────────────────────────────────────────────────────────────

/// Structural conversion of one parser-AST macro into the clean-AST macro. The
/// head/body terms are re-shaped 1:1 (parameters become `Var` terms); no
/// transform lives here.
fn macro_conv(m: &p::Macro) -> c::Macro {
    c::Macro {
        name: m.name.clone(),
        params: m.args.iter().map(|v| c::Term::Var(varspec(v))).collect(),
        body: term(&m.body),
    }
}

/// The whole `macros:` block, rendered by the clean crate (the always-break
/// vcat layout). Drop-in for the ported `render_parsed_macros` theory-body call.
pub fn macros_section(macros: &[p::Macro]) -> String {
    let ms: Vec<c::Macro> = macros.iter().map(macro_conv).collect();
    crate::pretty_clean::render_macros(&ms)
}

// ── predicates block ──────────────────────────────────────────────────────────

/// A contiguous run of `predicate:` declarations, rendered by the clean crate
/// (one `predicate: <fact><=><formula>` per predicate, blank-line separated).
/// Each item is `(predicate-fact NAME, formal PARAMS, BODY formula)`; the body
/// is supplied ALREADY arity-1 folded and sort-resolved (transforms stay
/// PORTED). Drop-in for the ported per-predicate `render_predicate` join.
pub fn predicates_section(items: &[(String, Vec<p::VarSpec>, p::Formula)]) -> String {
    let preds: Vec<c::Predicate> = items
        .iter()
        .map(|(name, params, body)| c::Predicate {
            name: name.clone(),
            params: params.iter().map(varspec).collect(),
            body: formula(body),
        })
        .collect();
    crate::pretty_clean::render_predicates(&preds)
}

//! Open-side adapters: translate live prover values into the clean
//! [`crate::producers`] crate's input model.
//!
//! These functions carry NO render logic — they only map already-computed
//! prover values (theory metadata, precomputed wellformedness banner, …) into
//! the behavioral input shape the clean fragment producers consume. The bytes
//! of every routed fragment are produced by the clean crate; this module is the
//! thin value bridge the integration protocol permits.

use crate::producers;
use crate::state::{TheoryEntry, TheoryOrigin};

/// Build the R1 `main/help` pane input from a loaded theory.
///
/// Mirrors exactly the inputs the ported `help_html` consumed: the theory name,
/// the `HH:MM:SS` load time, the `show origin` text (`Local "…"` / `Upload "…"`
/// / `Interactive`), and the precomputed `errors_html` wellformedness banner.
/// The clean [`producers::render_help_pane`] entity-escapes the name/time/origin
/// and appends the shared static help block + `{html,title}` envelope.
pub fn help_pane(entry: &TheoryEntry) -> producers::HelpPane {
    let origin = match &entry.origin {
        TheoryOrigin::Local(p) => format!("Local \"{}\"", p.display()),
        TheoryOrigin::Upload(n) => format!("Upload \"{}\"", n),
        TheoryOrigin::Interactive => "Interactive".to_string(),
    };
    producers::HelpPane {
        theory_name: entry.name.clone(),
        load_time: entry.loaded_at.format("%H:%M:%S").to_string(),
        origin,
        wf_banner_html: entry.errors_html.clone(),
    }
}

