214	/// HS `length (getClassifiedRules thy)._crProtocol` — the count shown in the
215	/// `Multiset rewriting rules … (N)` link.  Equal to the number of rules the
216	/// `main/rules` page renders (`extraACRules ++ protoRules`), i.e.
217	/// `web_proto_rules.len()` plus the ISend/IRecv-style intruder members of
218	/// `crProtocol` (`ctx.intruder_rules` minus construction/destruction rules).
219	fn proto_rule_count(entry: &TheoryEntry) -> usize {
220	    let proto = tamarin_theory::pretty_theory::web_proto_rules(
221	        &entry.parser_theory, &entry.typed_theory).len();
