242	/// HS `lemmaIndex` (`src/Web/Theory.hs:296-329`): the lemma header
243	/// (`lemma Name [attrs]: <tq> "<formula>"`), the `edit lemma`/`delete lemma`
244	/// links, the `proofIndex` tree, then a trailing `add lemma`.  The header +
245	/// edit/delete are wrapped by HS in `markStatus (root color)` — a `hl_*` span
246	/// the normalizer unwraps, so we emit them plain.
247	fn lemma_index(out: &mut String, entry: &TheoryEntry,
248	               l: &tamarin_theory::theory::Lemma<tamarin_theory::theory::ProofSkeleton>) {
249	    let idx = entry.idx;
250	    let tq = match l.trace_quantifier {
251	        TraceQuantifier::AllTraces => "all-traces",
252	        TraceQuantifier::ExistsTrace => "exists-trace",
253	    };
254	    let attrs = render_attrs(&l.attributes);
255	    // HS renders the quantifier + formula as `nest 2 (sep [tq, doubleQuotes
256	    // (prettyLNFormula f)])` (Web/Theory.hs:301-306) through the
257	    // HtmlDoc/HughesPJ engine: (1) AC argument lists (`++`/`*`/xor) are
258	    // stored AC-canonically (fAppAC flatten+sort, Term/Raw.hs:117-129);
259	    // (2) layout runs at the web width 100/67 (renderHtmlDoc,
260	    // Text/PrettyPrint/Html.hs:151-153); (3) fill widths are measured on
261	    // entity-ESCAPED text (Html.hs:102-105).  `pretty_formula` alone kept
262	    // source operand order and never wrapped, so `++`-operand order and
263	    // the fcat break-spaces inside tuples/AC chains diverged (the alethea
264	    // overview family).
265	    let canon = tamarin_theory::elaborate::canonicalize_ac_in_formula(&l.formula);
266	    // `nest 2 (sep [prettyTraceQuantifier tq, doubleQuotes (prettyLNFormula f)])`
267	    // — rendered under the active `HtmlDocGuard` (proof_state's), so operators
268	    // become `hl_operator` spans and the formula text is entity-escaped, while
269	    // the line-wrapping still measures escaped fill-widths at WEB_LINE_LENGTH/
270	    // WEB_RIBBON (the widths lib.rs installs) exactly as HS `renderHtmlDoc`.
271	    let formula_hdr = tamarin_theory::pretty_formula::lemma_header_line(tq, &canon);
272	    let n_url = url_path_escape(&l.name);
273	    use tamarin_theory::pretty_hpj as hpj;
274	    // HS `lemmaIndex` (Web/Theory.hs:301-321), a single Doc joined by `$-$`
275	    // (newline).  For a freshly-loaded (Unmarked) lemma `markStatus` is the
276	    // identity, so no wrapping colour span:
277	    //   kwLemma <-> prettyLemmaName l <> colon           -- "lemma NAME:"
278	    //   $-$ nest 2 (sep [tq, doubleQuotes formula])      -- the tq + formula
279	    //   $-$ (editLink <-> " or " <-> deleteLink)         -- note TWO spaces
280	    //   $-$ proofIndex $-$ text "" $-$ addLink
281	    // `bold`/name text is entity-escaped; `<->` contributes a single space, so
282	    // `editLink <-> " or " <-> deleteLink` renders `…edit</a>  or  <a…` (two
283	    // spaces around "or").
284	    out.push_str(&format!("{lemma} {name}{attrs}:\n",
285	        lemma = hpj::keyword_("lemma").render(),
286	        name = html_escape(&l.name),
287	        attrs = html_escape(&attrs)));
288	    out.push_str(&formula_hdr);
289	    out.push('\n');
290	    out.push_str(&format!(
291	        "<a class=\"internal-link edit\" href=\"/thy/trace/{idx}/main/edit/{n_url}\">edit lemma</a>  or  \
292	         <a class=\"internal-link delete\" href=\"/thy/trace/{idx}/main/delete/{n_url}\">delete lemma</a>\n",
293	        idx = idx, n_url = n_url));
294	    // `proofIndex l._lName tidx renderUrl mkRoute annPrf` — the annotated
295	    // proof tree, rendered by `prettyProofWith ppStep ppCase . insertPaths`.
296	    let live_root = entry.proof_state.as_ref().and_then(|ps| ps.get_root(&l.name));
297	    match live_root {
298	        Some(root) => {
299	            let cx = PpCtx { idx, lemma: &l.name, tq: l.trace_quantifier };
300	            let path: Vec<String> = Vec::new();
301	            pp_prf(out, &cx, &path, &root, 0);
302	        }
303	        None => {
304	            // No live proof state yet (lazily built): the lemma's root is a
305	            // fresh `Sorry Nothing`.  HS `proofIndex` of such a proof is
306	            // `ppCases (Sorry) [] = kwBy <> " " <> stepLink ["sorry-step"]`
307	            // (an `Unmarked`, unannotated-free `Sorry` step gets no
308	            // `remove-step`); the method text is `keyword_ "sorry"`.
309	            out.push_str(&format!(
310	                "{by} <a class=\"internal-link proof-step sorry-step\" \
311	                 href=\"/thy/trace/{idx}/main/proof/{n_url}\">{sorry}</a>",
312	                by = hpj::keyword_("by").render(),
313	                sorry = hpj::keyword_("sorry").render(),
314	                idx = idx, n_url = n_url));
315	        }
316	    }
317	    // `$-$ text "" $-$ addLink`.
318	    out.push_str("\n\n");
319	    out.push_str(&format!(
320	        "<a class=\"internal-link add\" href=\"/thy/trace/{idx}/main/add/{n_url}\">add lemma</a>",
321	        idx = idx, n_url = n_url));
322	}
