440	/// HS `proofIndex.ppStep` (`src/Web/Theory.hs:232-257`): a coloured
441	/// `proof-step` link carrying the pretty method, plus (unless the method is
442	/// `Sorry`) an empty `remove-step` link at the same path.  An unannotated
443	/// step (HS `psInfo == Nothing`) renders as a plain `hl_superfluous` span
444	/// instead of the proof-step link — but the `remove-step` link is appended
445	/// OUTSIDE that case split (`<>`, Web/Theory.hs:242-244), so it is emitted
446	/// for unannotated non-`Sorry` steps too.
447	///
448	/// The method text is `prettyProofMethod` laid out INSIDE the tree Doc
449	/// (`prettyProofWith`) by HS: at `nest (2*depth)` (one `nest 2` per named
450	/// case), with the leaf's `by ` prefix beside it, at the HtmlDoc width
451	/// (100/67, entity fill-widths).  Reproduce that layout exactly by
452	/// rendering `nest (2·depth) ("by "? <> method)` under the entity guard,
453	/// then stripping the indent/`by ` back off the first line (the `<a>`
454	/// wraps only the method text; continuation-line whitespace is
455	/// canonicalized by the gate, break positions are what must match).
456	fn pp_step(out: &mut String, cx: &PpCtx, path: &[String], node: &ProofNode,
457	           depth: usize, by_prefix: bool) {
458	    use tamarin_theory::pretty_hpj::{self as hpj, Doc, WEB_LINE_LENGTH, WEB_RIBBON};
459	    // Render `("by "? <> prettyProofMethod)` at `nest (2*depth)` under the
460	    // ACTIVE `HtmlDocGuard` (proof_state's), so the method carries its `hl_*`
461	    // spans and the wrap budget accounts for the `by ` offset exactly as HS.
462	    // The `by ` is a plain `Doc::text` here purely to size the budget; it is
463	    // stripped back off and re-emitted as `keyword_ "by"` OUTSIDE the link.
464	    let rendered = {
465	        let mut doc =
466	            tamarin_theory::pretty_theory::pretty_proof_method_doc(&node.method);
467	        if by_prefix {
468	            doc = Doc::text("by ").beside(doc);
469	        }
470	        doc.nest((2 * depth) as isize)
471	            .render_with(WEB_LINE_LENGTH, WEB_RIBBON)
472	    };
473	    // Strip the first line's nest indent (and the sizing `by `) so the `<a>`
474	    // wraps only the method text; continuation lines keep their absolute
475	    // indentation (→ `&nbsp;` via postprocess).  The stripped text ALREADY
476	    // carries `hl_*` spans — do NOT entity-escape it again.
477	    let mut label: &str = rendered.trim_start_matches(' ');
478	    if by_prefix {
479	        label = label.strip_prefix("by ").unwrap_or(label);
480	    }
481	    // Leading indent for this line (HS `nest 2` per named case).  The `by `
482	    // prefix is HS `prettyCase ps (kwBy <> text " ")` = `markStatus ps` wrapping
483	    // `keyword_ "by"` PLUS its trailing space (Theory/Proof.hs:1080-1101, see line 1084).
484	    let ind = "  ".repeat(depth);
485	    out.push_str(&ind);
486	    if by_prefix {
487	        let (mo, mc) = mark_wrap(cx, node);
488	        out.push_str(&format!("{}{} {}", mo, hpj::keyword_("by").render(), mc));
489	    }
490	    let url = format!(
491	        "/thy/trace/{idx}/main/proof/{lemma}{path}",
492	        idx = cx.idx, lemma = url_path_escape(cx.lemma), path = encode_sub_path(path));
493	    if !node.annotated {
494	        // `superfluousStep = withTag "span" [("class","hl_superfluous")] ppMethod`.
495	        // HS appends `removeStep` regardless of the annotation branch
496	        // (Web/Theory.hs:242-244) — only a `Sorry` method skips it.  Seen on
497	        // noise secrecy_4_passiveINpsk1_proof.spthy: the kept-verbatim
498	        // (unannotated) subtrees under drifted nested split_case steps carry
499	        // one empty remove-step anchor per node in HS's /overview/help.
500	        out.push_str(&format!("<span class=\"hl_superfluous\">{}</span>", label));
501	        if !matches!(node.method, ProofMethod::Sorry(_)) {
502	            out.push_str(&format!(
503	                "<a class=\"internal-link remove-step\" href=\"{url}\"></a>", url = url));
504	        }
505	        return;
506	    }
507	    let color = interpret_color(cx.tq, proof_status(node));
508	    let cls = match color {
509	        StepColor::Unmarked => "sorry-step",
510	        StepColor::Green => "hl_good",
511	        StepColor::Red => "hl_bad",
512	        StepColor::Yellow => "hl_medium",
513	    };
514	    out.push_str(&format!(
515	        "<a class=\"internal-link proof-step {cls}\" href=\"{url}\">{label}</a>",
516	        cls = cls, url = url, label = label));
517	    // `invalidatedStep`: an `Invalidated` step also gets a `verify it` link.
518	    if color == StepColor::Yellow && matches!(node.method, ProofMethod::Invalidated) {
519	        out.push_str(&format!(
520	            " <a class=\"internal-link hl_medium\" href=\"/thy/trace/{idx}/verify/proof/{lemma}\">verify it</a>",
521	            idx = cx.idx, lemma = url_path_escape(cx.lemma)));
522	    }
523	    // `<> case psMethod step of Sorry _ -> emptyDoc; _ -> removeStep`.
524	    if !matches!(node.method, ProofMethod::Sorry(_)) {
525	        out.push_str(&format!(
526	            "<a class=\"internal-link remove-step\" href=\"{url}\"></a>", url = url));
527	    }
528	}
