701	/// `postprocessHtmlDoc` (the caller `vcat`-joins fragments with `\n` and
702	/// postprocesses once): `<h2>HEADER</h2>` on its own line (from `$$`), then the
703	/// zero-width `<p …>` open glued before `body`'s first line and `</p>` after
704	/// its last (`withTag`).  `body` is already escaped + span-marked (rendered
705	/// under [`HtmlDocGuard`]); `header` is `text header` so it is entity-escaped
706	/// too.
707	fn section_fragment(header: &str, class: &str, body: &str) -> String {
708	    format!(
709	        "<h2>{}</h2>\n<p class=\"{}\">{}</p>",
710	        tamarin_theory::pretty_hpj::escape_html_entities(header),
711	        class,
712	        body,
713	    )
714	}
715	
716	/// HS `ppWithHeader` (Web/Theory.hs:912-917): like [`section_fragment`] but the
717	/// whole section is `emptyDoc` (omitted from the `vcat`) when `body` is empty
718	/// (`caseEmptyDoc emptyDoc … body`).
719	fn with_header_fragment(header: &str, class: &str, body: &str) -> Option<String> {
720	    if body.is_empty() { None } else { Some(section_fragment(header, class, body)) }
721	}
722	
723	/// `vcat` the pane fragments (HS `messageSnippet`/`rulesSnippet` top-level
724	/// `vcat`) then `postprocessHtmlDoc` once (leading spaces → `&nbsp;`, `<br/>`
725	/// per line).  `None` fragments are HS `emptyDoc` and vanish (`emptyDoc $$ x =
726	/// x`); an empty `String` fragment is HS `text ""` (a real blank line, e.g. the
727	/// absent-macros slot).
728	fn assemble_pane(fragments: Vec<Option<String>>) -> String {
729	    let pieces: Vec<String> = fragments.into_iter().flatten().collect();
730	    tamarin_theory::pretty_hpj::postprocess_html(&pieces.join("\n"))
731	}
732	
733	/// HS `messageSnippet` (Web/Theory.hs:920-931): Signature +
734	/// Construction/Deconstruction rule sections.
735	fn message_html(entry: &TheoryEntry) -> String {
736	    // HS renders `messageSnippet` through the `HtmlDoc Doc` transformer (same
737	    // `pp = renderHtmlDoc` dispatch as `rulesSnippet`, Web/Theory.hs:1014-1015):
738	    // every `text`/`char` is entity-escaped + measured escaped, keywords/
739	    // operators become `hl_*` spans, and the whole doc is postprocessed
740	    // (`<br/>`/`&nbsp;`).  Enable HtmlDoc mode for the pane build.
741	    let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
742	    // `prettySignatureWithMaude thy._thySignature` — the same signature block
743	    // the theory body prints.
744	    let sig_block = tamarin_theory::pretty_theory::web_signature_block(
745	        &entry.typed_theory.signature.maude_sig);
746	    // `getClassifiedRules thy`'s `_crConstruct` / `_crDestruct`.  RS stores
747	    // proto rules separately, so `ctx.intruder_rules` is exactly HS's
748	    // `intrRulesAC`; an order-preserving filter reproduces the classification.
749	    let mut construct: Vec<IntrRuleAC> = Vec::new();
750	    let mut destruct: Vec<IntrRuleAC> = Vec::new();
751	    if let Some(ps) = &entry.proof_state {
752	        let ctx = ps.ctx.lock();
753	        for ir in &ctx.intruder_rules {
754	            if is_constr_intr(&ir.info) { construct.push(ir.clone()); }
755	            else if is_destr_intr(&ir.info) { destruct.push(ir.clone()); }
756	        }
757	    }
758	    // `map prettyRuleAC` joined by one blank line == `pretty_intruder_variants`
759	    // (HS `vcat (intersperse (text "") s)`).
760	    let construct_block = tamarin_theory::pretty_formula::pretty_intruder_variants(&construct);
761	    let destruct_block = tamarin_theory::pretty_formula::pretty_intruder_variants(&destruct);
762	    // HS `messageSnippet = vcat [ppSection "Signature" …, ppSection
763	    // "Construction Rules" …, ppSection "Deconstruction Rules" …]`.  `ppSection`
764	    // is ALWAYS emitted (even with an empty body), unlike `ppWithHeader`.
765	    assemble_pane(vec![
766	        Some(section_fragment("Signature", "monospace rules", &sig_block)),
767	        Some(section_fragment("Construction Rules", "monospace rules", &construct_block)),
768	        Some(section_fragment("Deconstruction Rules", "monospace rules", &destruct_block)),
769	    ])
770	}
771	
772	/// HS `showInjFact` (Web/Theory.hs:906-910): `showFactTag tag ++ "(" ++
773	/// intercalate "," ("id":positions) ++ ")"`.
774	fn show_inj_fact(
775	    tag: &tamarin_theory::fact::FactTag,
776	    behaviours: &[Vec<tamarin_theory::tools::injective_fact_instances::MonotonicBehaviour>],
777	) -> String {
778	    use tamarin_theory::fact::{FactTag, Multiplicity};
779	    let name = tamarin_theory::fact::fact_tag_name(tag);
780	    let head = match tag {
781	        FactTag::Proto(Multiplicity::Persistent, _, _) => format!("!{}", name),
782	        _ => name.to_string(),
783	    };
784	    let mut parts: Vec<String> = vec!["id".to_string()];
785	    for bb in behaviours {
786	        if bb.len() == 1 {
787	            parts.push(bb[0].to_string());
788	        } else {
789	            let inner: Vec<String> = bb.iter().map(|b| b.to_string()).collect();
790	            parts.push(format!("({})", inner.join(",")));
791	        }
792	    }
793	    format!("{}({})", head, parts.join(","))
794	}
795	
796	/// HS `rulesSnippet` (Web/Theory.hs:887-917).
797	fn rules_html(entry: &TheoryEntry) -> String {
798	    // HS renders `rulesSnippet` through the `HtmlDoc Doc` transformer
799	    // (`HtmlDocument d => ClosedTheory -> d`, Web/Theory.hs:887-917, laid out by
800	    // `renderHtmlDoc`): every `text`/`char` is entity-escaped + measured
801	    // escaped, keywords/operators/comments become `hl_*` spans, and the whole
802	    // doc is postprocessed.  The batch `--prove` theory printer calls the SAME
803	    // renderers WITHOUT the guard and is unaffected (thread-local).
804	    let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
805	    use tamarin_theory::pretty_hpj::{escape_html_entities, multi_comment_};
806	    // HS `rulesSnippet`'s FIRST slot: `if null (theoryMacros thy) then text
807	    // empty else ppWithHeader "Macros" (prettyMacros ...)` — a `text ""` blank
808	    // line when there are no macros, else the macros section.
809	    let macros_block = tamarin_theory::pretty_theory::web_macros(&entry.parser_theory);
810	    let proto_rules = tamarin_theory::pretty_theory::web_proto_rules(
811	        &entry.parser_theory, &entry.typed_theory);
812	    let mut inj_body = String::from("None");
813	    let mut extra_ac: Vec<String> = Vec::new();
814	    if let Some(ps) = &entry.proof_state {
815	        let ctx = ps.ctx.lock();
816	        // `getInjectiveFactInsts thy` — already computed on the context.
817	        if !ctx.injective_fact_insts.is_empty() {
818	            let items: Vec<String> = ctx.injective_fact_insts.iter()
819	                .map(|(tag, behaviours)| show_inj_fact(tag, behaviours))
820	                .collect();
821	            inj_body = items.join(", ");
822	        }
823	        // `extraACRules` = `_crProtocol` not already in `theoryRules` (ISend,
824	        // IRecv).  HS `prettyIntruderRuleAC r = prettyRuleAC r $--$ nest 2
825	        // (multiComment_ ["has exactly the trivial AC variant"]) $--$ text ""`
826	        // (Web/Theory.hs:887-917, see line 911): body, blank line, indent-2 comment, blank line,
827	        // trailing empty line.  Rendered as a string that is `vcat`-joined
828	        // (`\n`) with the other rules below.
829	        let comment = multi_comment_(&["has exactly the trivial AC variant"]).render();
830	        for ir in &ctx.intruder_rules {
831	            if is_constr_intr(&ir.info) || is_destr_intr(&ir.info) { continue; }
832	            let body = tamarin_theory::pretty_formula::pretty_intruder_variants(
833	                std::slice::from_ref(ir));
834	            extra_ac.push(format!("{body}\n\n  {comment}\n\n"));
835	        }
836	    }
837	    // `vcat (map prettyIntruderRuleAC extraACRules ++ map prettyClosedProtoRule
838	    // protoRules)` — `vcat` = `$$`, i.e. join with a single `\n`.  Each
839	    // rule string already carries its own internal blank lines (intruder rules
840	    // end with a trailing blank; proto rules end at the comment), so the
841	    // resulting blank-line structure matches HS byte-for-byte.
842	    let mut msr_parts = extra_ac;
843	    msr_parts.extend(proto_rules);
844	    let msr_body = msr_parts.join("\n");
845	    // `vsep $ map prettyRestriction` (Web/Theory.hs:887-917, see line 895) = `foldr ($--$)` =
846	    // blank line between restrictions.
847	    let restr_body = tamarin_theory::pretty_theory::web_restrictions(
848	        &entry.parser_theory, &entry.typed_theory).join("\n\n");
849	
850	    // HS `rulesSnippet` order: Macros slot → Fact Symbols → MSR → Restrictions.
851	    let macros_slot = match &macros_block {
852	        // HS `ppWithHeader "Macros"` — omitted iff the body is empty.
853	        Some(m) => with_header_fragment("Macros", "monospace rules", m),
854	        // HS `text empty` — a real blank line.
855	        None => Some(String::new()),
856	    };
857	    assemble_pane(vec![
858	        macros_slot,
859	        with_header_fragment(
860	            "Fact Symbols with Injective Instances", "monospace rules",
861	            &escape_html_entities(&inj_body)),
862	        with_header_fragment("Multiset Rewriting Rules", "monospace rules", &msr_body),
863	        with_header_fragment(
864	            "Restrictions of the Set of Traces", "monospace rules", &restr_body),
865	    ])
866	}
867	
868	/// HS `reqCasesSnippet` + `htmlSource` (Web/Theory.hs:820-879): the raw/refined
869	/// source-case listing.  The `src_idx`/`case_idx` URL fields are ignored (HS
870	/// `TheorySource kind _ _` renders the whole `getSource kind thy` list); they
871	/// only address the per-case interactive graph.
872	fn sources_html(entry: &TheoryEntry, kind: &SourceKind) -> String {
873	    // HS renders `reqCasesSnippet = vcat (htmlSource <$> …)` through the
874	    // `HtmlDoc Doc` transformer + `renderHtmlDoc` (Web/Theory.hs:1005-1144, see line 1016): the
875	    // goal headers, per-case sequents (`pretty_non_graph_system`) and all
876	    // structural tags are entity-escaped + span-marked and postprocessed once.
877	    let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
878	    let (kind_str, want_refined) = match kind {
879	        SourceKind::Raw => ("raw", false),
880	        SourceKind::Refined => ("refined", true),
881	    };
882	    let source_lists = compute_source_lists(entry, want_refined);
883	    // `vcat` the per-source blocks (join with `\n`), then `postprocessHtmlDoc`.
884	    let blocks: Vec<String> = source_lists.iter().enumerate()
885	        .map(|(j, (goal, cases))| render_html_source(entry.idx, kind_str, j + 1, goal, cases))
886	        .collect();
887	    tamarin_theory::pretty_hpj::postprocess_html(&blocks.join("\n"))
888	}
889	
890	/// Compute `getSource kind thy` — the raw or refined source list, as
891	/// `(goal, cases)` pairs.  Shared by `sources_html` (the page) and
892	/// `source_case_counts` (the theory-index `(N cases, …)` annotation) so both
893	/// stay consistent.  Returns empty when the proof state is not yet built.
894	fn compute_source_lists(
895	    entry: &TheoryEntry,
896	    want_refined: bool,
897	) -> Vec<(tamarin_theory::constraint::constraints::Goal,
898	         Vec<(String, tamarin_theory::constraint::system::System)>)> {
899	    use tamarin_theory::constraint::system::SourceKind as SysSourceKind;
900	    let Some(ps) = &entry.proof_state else { return Vec::new(); };
901	    // Saturation (`s.cases(&ctx)` → `ensure_saturated`) and
902	    // `refine_with_source_asms` run solver code; `formula_to_guarded` on
903	    // the `[sources]`-lemma formulas resolves user fun symbols.  All via
904	    // thread-locals — install them (see `ProofState::user_funs`).
905	    let _user_funs_guard = ps.install_user_funs();
906	    let ctx = ps.ctx.lock();
907	    // Refined sources fold in the `[sources]`-lemma typing assumptions
908	    // (HS `refineWithSourceAsms`, Rule.hs:157).  With no such lemma the refine
909	    // is a plain relabel to `RefinedSource` (Sources.hs:617-618).
910	    let typ_asms: Vec<tamarin_theory::guarded::Guarded> = if want_refined {
911	        entry.typed_theory.lemmas()
912	            .filter(|l| matches!(l.trace_quantifier, TraceQuantifier::AllTraces)
913	                && l.attributes.iter().any(|a| matches!(a, LemmaAttr::Sources)))
914	            .filter_map(|l| tamarin_theory::guarded::formula_to_guarded(&l.formula).ok())
915	            .collect()
916	    } else { Vec::new() };
917	
918	    // `getSource kind thy`: raw = `ctx.full_sources` (precomputed + saturated);
919	    // refined = raw with `refineWithSourceAsms` applied (or relabeled).
920	    if want_refined && !typ_asms.is_empty() {
921	        let cloned: Vec<_> = ctx.full_sources.iter()
922	            .map(|s| { let _ = s.cases(&ctx); s.clone() }).collect();
923	        let refined = tamarin_theory::constraint::solver::sources::refine_with_source_asms(
924	            cloned, &typ_asms, &ctx);
925	        refined.iter().map(|s| (s.goal.clone(), s.cases_or_empty())).collect()
926	    } else {
927	        ctx.full_sources.iter().map(|s| {
928	            let mut cases = s.cases(&ctx);
929	            if want_refined {
930	                for (_, sys) in cases.iter_mut() {
931	                    sys.source_kind = Some(SysSourceKind::RefinedSources);
932	                }
933	            }
934	            (s.goal.clone(), cases)
935	        }).collect()
936	    }
937	}
938	
939	/// HS `casesInfo kind` (Web/Theory.hs:399-406): `(nCases, chainInfo)` where
940	/// `nCases = length (getSource kind thy)` and `nChains = sum $ map (sum .
941	/// unsolvedChainConstraints)`.  Rendered as `(N cases, deconstructions
942	/// complete)` or `(N cases, K partial deconstructions left)`.
943	fn source_case_counts(entry: &TheoryEntry, want_refined: bool) -> (usize, usize) {
944	    let source_lists = compute_source_lists(entry, want_refined);
945	    let n_cases = source_lists.len();
946	    let n_chains: usize = source_lists.iter()
947	        .flat_map(|(_, cases)| cases.iter())
948	        .map(|(_, sys)|
949	            tamarin_theory::constraint::solver::sources::unsolved_chain_constraints(sys))
950	        .sum();
951	    (n_cases, n_chains)
952	}
953	
954	/// HS `htmlSource` (Web/Theory.hs:820-845) for a single [`Source`] — returns
955	/// the pre-`postprocessHtmlDoc` fragment (the caller `vcat`-joins with `\n`
956	/// then postprocesses once).  Must be called under an [`HtmlDocGuard`] so the
957	/// goal + sequent render escaped + span-marked.
958	fn render_html_source(
959	    idx: usize,
960	    kind: &str,
961	    j: usize,
962	    goal: &tamarin_theory::constraint::constraints::Goal,
963	    cases: &[(String, tamarin_theory::constraint::system::System)],
964	) -> String {
965	    use tamarin_theory::pretty_hpj::escape_html_entities;
966	    let n_cases = cases.len();
967	    // `withTag "p" [] ppPrem` — the per-case premise paragraph, built as ONE
968	    // Doc so the goal wraps (continuation `&nbsp;`/`<br/>`) exactly as HS.
969	    let prem_p = tamarin_theory::pretty_theory::web_pretty_source_prem(goal);
970	    // `withTag "h2" [] ppHeader`, `ppHeader = hsep [text "Sources of" <-> ppPrem,
971	    // parens (nCases <-> "cases")]` — the whole header is ONE Doc so the goal
972	    // wraps at the width WITH the `Sources of ` prefix offset.
973	    let header = format!("<h2>{}</h2>",
974	        tamarin_theory::pretty_theory::web_pretty_source_header(goal, n_cases));
975	    if cases.is_empty() {
976	        // HS `withTag "h2" [] ppHeader $-$ withTag "h3" [] (text "No cases.")`.
977	        return format!("{header}\n<h3>No cases.</h3>");
978	    }
979	    // `vcat (h2 : concatMap ppCase cases)` — each `ppCase` is [h3, static-graph,
980	    // p-prem, p-cases]; all joined with `\n`.
981	    let mut parts: Vec<String> = vec![header];
982	    for (i, (name, sys)) in cases.iter().enumerate() {
983	        let ii = i + 1;
984	        // `isPartial = not (null (unsolvedChains se))`.
985	        let is_partial =
986	            tamarin_theory::constraint::solver::sources::unsolved_chain_constraints(sys) != 0;
987	        let partial = if is_partial { "(partial deconstructions)" } else { "" };
988	        // HS `fsep [text "Source", int i, text "of", nCases, text " / named ",
989	        // doubleQuotes (text name), partial]` — `fsep` single-spaces, and the
990	        // ` / named ` text keeps its own surrounding spaces (→ double spaces),
991	        // and the trailing (possibly empty) `partial` element is preceded by an
992	        // `fsep` space (→ trailing space even when not partial).
993	        parts.push(format!(
994	            "<h3>Source {i} of {n}  / named  &quot;{name}&quot; {partial}</h3>",
995	            i = ii, n = n_cases, name = escape_html_entities(name), partial = partial,
996	        ));
997	        // `refDotInteractiveStaticPath = withTag "static-graph"
998	        // [("graphSrc", srcPath)] (text "")` — note the capital-S `graphSrc`.
999	        parts.push(format!(
1000	            "<static-graph graphSrc=\"/thy/trace/{idx}/intdot/cases/{kind}/{j}/{i}\"></static-graph>",
1001	            idx = idx, kind = kind, j = j, i = ii,
1002	        ));
1003	        // `withTag "p" [] ppPrem`.
1004	        parts.push(prem_p.clone());
1005	        // `wrapP (prettyNonGraphSystem se)`, `wrapP = withTag "p"
1006	        // [("class","monospace cases")]`.  The sequent renders under the guard.
1007	        parts.push(format!(
1008	            "<p class=\"monospace cases\">{}</p>",
1009	            tamarin_theory::pretty_system::pretty_non_graph_system(sys)));
1010	    }
1011	    parts.join("\n")
1012	}
1013

