    // renderer — the parser produces left-associative nested `BinOp` chains for
    // multiset/xor operators, but HS's `fAppAC` flattens+sorts at parse time
    // (a solver-side transform).  The clean crate renders the facts as given,
    // so the canonicalisation stays PORTED here.
    use crate::elaborate::canonicalize_ac_in_pfact;
    let e_prems: Vec<p::Fact> = premises.iter().map(canonicalize_ac_in_pfact).collect();
    let e_acts: Vec<p::Fact> = actions.iter().map(canonicalize_ac_in_pfact).collect();
    let e_concs: Vec<p::Fact> = conclusions.iter().map(canonicalize_ac_in_pfact).collect();

