/// The `Multiset Rewriting Rules` rules-pane body: FULL rule blocks with their
/// AC/E-dependent blank-line separators, rendered by the clean crate.
pub fn msr_body(rules: &[MsrRuleInput]) -> String {
    let clean: Vec<(c::Rule, Option<c::AcVariants>)> = rules
        .iter()
        .map(|m| {
            let e = c::Rule {
                name: m.name.clone(),
                modulo: Some(m.modulo.clone()),
                attributes: m.attrs.iter().map(rule_attr).collect(),
                premises: m.prems.iter().map(fact).collect(),
                actions: m.acts.iter().map(fact).collect(),
                conclusions: m.concs.iter().map(fact).collect(),
                loop_breakers: m.loop_breakers.clone(),
            };
            let v = m.variants.as_ref().map(|v| c::AcVariants {
                ac_rule: c::Rule {
                    name: m.name.clone(),
                    modulo: Some("AC".to_string()),
                    attributes: v.attrs.iter().map(rule_attr).collect(),
                    premises: v.prems.iter().map(fact).collect(),
                    actions: v.acts.iter().map(fact).collect(),
                    conclusions: v.concs.iter().map(fact).collect(),
                    loop_breakers: v.loop_breakers.clone(),
                },
                substitutions: v
                    .substitutions
                    .iter()
                    .map(|g| g.iter().map(|(l, r)| (term(l), term(r))).collect())
                    .collect(),
            });
            (e, v)
        })
        .collect();
    crate::pretty_clean::web::render_msr_body(&clean)
}

