                    loop_breakers: v.loop_breakers.clone(),
                },
                substitutions: v
                    .substitutions
                    .iter()
                    .map(|g| g.iter().map(|(l, r)| (term(l), term(r))).collect())
                    .collect(),
            });
            (e, v)
        })
        .collect();
    crate::pretty_clean::web::render_msr_body(&clean)
}

/// The `Restrictions of the Set of Traces` rules-pane body: restriction blocks
/// joined by one blank line, rendered by the clean crate. Each item is
/// `(name, statement, expanded)` with both formulas already predicate-expanded,
/// arity-1 folded, AC-canonicalised and sort-resolved ported-side.
pub fn restrictions_body(items: &[(String, p::Formula, p::Formula)]) -> String {
    let clean: Vec<c::Restriction> = items
        .iter()
        .map(|(name, stmt, exp)| c::Restriction {
            name: name.clone(),
            formula: formula(stmt),
            expanded: formula(exp),
        })
        .collect();
    crate::pretty_clean::web::render_restrictions_body(&clean)
}

