/// The `Multiset Rewriting Rules` rules-pane body (R6 web mode): the
/// `extraACRules` intruder rules (ISend/IRecv, supplied pre-classified by the
/// caller) followed by the user protocol rules, each a FULL rule block with its
/// AC/E-dependent blank-line separators, rendered by the clean crate through
/// `pretty_clean_adapt::msr_body`.
pub fn web_msr_body(
    parsed: &p::Theory,
    elaborated: &Theory,
    extra_ac: &[crate::rule::IntrRuleAC],
) -> String {
    let (macros, _preds) = collect_macros_predicates(parsed);
    let arity1 = arity1_noeq_names(elaborated);
    let manual_variants = contains_manual_rule_variants(parsed, elaborated, false);
    let mut msr: Vec<crate::pretty_clean_adapt::MsrRuleInput> = Vec::new();
    // `extraACRules` — `_crProtocol` intruder rules not in `theoryRules`. Their
    // LN body is already AC-normalised, so no `canonicalize_ac_in_pfact` pass.
    for ir in extra_ac {
        msr.push(crate::pretty_clean_adapt::MsrRuleInput {
            name: crate::pretty_formula::intr_rule_name(ir),
            modulo: "AC".to_string(),
            attrs: Vec::new(),
            prems: lnfacts_to_parser(&ir.premises),
            acts: lnfacts_to_parser(&ir.actions),
            concs: lnfacts_to_parser(&ir.conclusions),
            loop_breakers: Vec::new(),
            variants: None,
        });
    }
    for item in &parsed.items {
        if let p::TheoryItem::Rule(r) = item {
            if elaborated.rules().any(|er| er.name() == r.name) {
                msr.push(rule_msr_input(r, elaborated, &macros, &arity1, manual_variants, false));
            }
        }
    }
    crate::pretty_clean_adapt::msr_body(&msr)
}

/// The `Restrictions of the Set of Traces` rules-pane body (R6 web mode):
/// restriction blocks joined by one blank line, rendered by the clean crate
/// through `pretty_clean_adapt::restrictions_body`. Reuses the batch
/// restriction transforms (`restriction_web_input`) so the web block is the
/// same model the batch echo routes.
pub fn web_restrictions_body(parsed: &p::Theory, elaborated: &Theory) -> String {
    let (macros, predicates) = collect_macros_predicates(parsed);
    let arity1 = arity1_noeq_names(elaborated);
    let items: Vec<(String, p::Formula, p::Formula)> = parsed
        .items
        .iter()
        .filter_map(|item| match item {
            p::TheoryItem::Restriction(r) | p::TheoryItem::LegacyAxiom(r) => {
                Some(restriction_web_input(r, &macros, &predicates, &arity1))
            }
            _ => None,
        })
        .collect();
    crate::pretty_clean_adapt::restrictions_body(&items)
}

