// ── R6 web center panes: main/message + main/rules ───────────────────────────
//
// The pane BODIES are produced by the clean `pretty_clean` web renderer (rule /
// signature / restriction text, entity-escaped + `hl_*` spanned, at web params);
// the `<h2>`/`<p>` section skin + per-line postprocess + `{html,title}` envelope
// come from the clean `producers` skin. These adapters only extract the live
// prover values (classified intruder rules, injective-fact instances) and shape
// them into the producers input; no render logic lives here.

use tamarin_theory::rule::IntrRuleAC;

/// One producer content block (heading + clean-rendered body split into logical
/// lines), with the empty-body mode the section uses.
fn block(heading: &str, body: String, when_empty: producers::EmptyRender) -> producers::HeadedBlock {
    producers::HeadedBlock {
        heading: heading.to_string(),
        body: producers::Content {
            lines: body.split('\n').map(str::to_string).collect(),
        },
        when_empty,
    }
}

/// The `main/message` pane: Signature + Construction/Deconstruction rule
/// sections. `messageSnippet` (Web/Theory.hs:920-931) always emits every
/// `ppSection` (even with an empty body).
pub fn message_pane(entry: &crate::state::TheoryEntry) -> producers::ContentPane {
    use producers::EmptyRender::Keep;
    let sig_body = tamarin_theory::pretty_clean_adapt::web_signature_body(
        &entry.typed_theory.signature.maude_sig);
    // `getClassifiedRules thy`'s `_crConstruct` / `_crDestruct` — an
    // order-preserving filter over `ctx.intruder_rules` (== HS `intrRulesAC`).
    let mut construct: Vec<IntrRuleAC> = Vec::new();
    let mut destruct: Vec<IntrRuleAC> = Vec::new();
    if let Some(ps) = &entry.proof_state {
        let ctx = ps.ctx.lock();
        for ir in &ctx.intruder_rules {
            if super::theory_html::is_constr_intr(&ir.info) {
                construct.push(ir.clone());
            } else if super::theory_html::is_destr_intr(&ir.info) {
                destruct.push(ir.clone());
            }
        }
    }
    let construct_body = tamarin_theory::pretty_formula::web_intruder_variants(&construct);
    let destruct_body = tamarin_theory::pretty_formula::web_intruder_variants(&destruct);
    producers::ContentPane {
        title: "Message theory".to_string(),
        blocks: vec![
            block("Signature", sig_body, Keep),
            block("Construction Rules", construct_body, Keep),
            block("Deconstruction Rules", destruct_body, Keep),
        ],
    }
}

/// The `main/rules` pane: Macros slot, Fact Symbols with Injective Instances,
/// Multiset Rewriting Rules, Restrictions of the Set of Traces.
pub fn rules_pane(entry: &crate::state::TheoryEntry) -> producers::ContentPane {
    use producers::EmptyRender::{BlankLine, Omit};
    // HS `rulesSnippet`'s FIRST slot: `if null macros then text "" else
    // ppWithHeader "Macros" …` — a blank line when there are no macros.
    let macros_block = tamarin_theory::pretty_theory::web_macros(&entry.parser_theory);
    let mut inj_body = String::from("None");
    let mut extra_ac: Vec<IntrRuleAC> = Vec::new();
    if let Some(ps) = &entry.proof_state {
        let ctx = ps.ctx.lock();
        if !ctx.injective_fact_insts.is_empty() {
            let items: Vec<String> = ctx
                .injective_fact_insts
                .iter()
                .map(|(tag, behaviours)| super::theory_html::show_inj_fact(tag, behaviours))
                .collect();
            inj_body = items.join(", ");
        }
        // `extraACRules` = `_crProtocol` not already in `theoryRules`.
        for ir in &ctx.intruder_rules {
            if super::theory_html::is_constr_intr(&ir.info)
                || super::theory_html::is_destr_intr(&ir.info)
            {
                continue;
            }
            extra_ac.push(ir.clone());
        }
    }
    let inj_body = crate::producers::html::escape_text(&inj_body);
    let msr_body = tamarin_theory::pretty_theory::web_msr_body(
        &entry.parser_theory, &entry.typed_theory, &extra_ac);
    let restr_body = tamarin_theory::pretty_theory::web_restrictions_body(
        &entry.parser_theory, &entry.typed_theory);

    // HS `ppWithHeader "Macros"` — omitted (blank line) when the body is empty,
    // else the section; the corpus never carries theory macros in this pane.
    let macros_slot = match macros_block {
        Some(m) => block("Macros", m, Omit),
        None => producers::HeadedBlock {
            heading: "Macros".to_string(),
            body: producers::Content { lines: vec![String::new()] },
            when_empty: BlankLine,
        },
    };
    producers::ContentPane {
        title: "Multiset rewriting rules and restrictions".to_string(),
        blocks: vec![
            macros_slot,
            block("Fact Symbols with Injective Instances", inj_body, Omit),
            block("Multiset Rewriting Rules", msr_body, Omit),
            block("Restrictions of the Set of Traces", restr_body, Omit),
        ],
    }
}

/// Render a content pane to its BODY (the `<h2>`/`<p>` document, per-line
/// postprocessed) WITHOUT the `{html,title}` envelope — for the overview page
/// which embeds the main view as raw HTML. The enveloped `main/*` responses use
/// [`producers::render_content_pane`]; this mirrors its body assembly.
pub fn render_pane_body(pane: &producers::ContentPane) -> String {
    use producers::EmptyRender;
    let mut chunks: Vec<String> = Vec::new();
    for b in &pane.blocks {
        if b.body.is_empty() {
            match b.when_empty {
                EmptyRender::Omit => continue,
                EmptyRender::BlankLine => {
                    chunks.push(String::new());
                    continue;
                }
                EmptyRender::Keep => {}
            }
        }
        let mut chunk = String::new();
        chunk.push_str("<h2>");
        chunk.push_str(&crate::producers::html::escape_text(&b.heading));
        chunk.push_str("</h2>\n<p class=\"monospace rules\">");
        chunk.push_str(&b.body.lines.join("\n"));
        chunk.push_str("</p>");
        chunks.push(chunk);
    }
    crate::producers::html::postprocess_lines(&chunks.join("\n"))
}

